import { HealthService } from '../../services/health.service.js';
import { navigate } from '../../router.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import './health-day-detail/health-day-detail.component.js';
import { ACTIVITY_TYPES } from '@motivation/shared';
import {
    HEALTH_EVENTS,
    type AddWorkoutEvent,
    type AddFoodEvent,
    type EditFoodEvent,
    type EditWorkoutEvent,
} from './health-events.js';
import type { HealthDayDetail } from './health-day-detail/health-day-detail.component.js';
import type { ConsumptionEntry, Activity, ActivityType } from '@motivation/shared';
import type { ScreenComponent } from '../../types/screen-component.js';
import { createComponentLogger } from '../../utils/component-logger.js';
import { safeExec } from '../../utils/safe-exec.js';

const addActivityTemplate = document.createElement('template');
addActivityTemplate.innerHTML = `
    <dialog class="activity-dialog" id="activity-dialog">
        <form method="dialog" id="activity-form">
            <h2>Log Activity</h2>
            <div class="form-group">
                <label for="act-title">Title</label>
                <input type="text" id="act-title" required placeholder="e.g. Morning run">
            </div>
            <div class="form-group">
                <label for="act-type">Type</label>
                <select id="act-type">
                    ${ACTIVITY_TYPES.map((type) => `<option value="${type}">${type.charAt(0).toUpperCase() + type.slice(1).replace('-', ' ')}</option>`).join('')}
                </select>
            </div>
            <div class="form-group">
                <label for="act-date">Date</label>
                <input type="date" id="act-date" required>
            </div>
            <div class="form-group">
                <label for="act-duration">Duration (minutes)</label>
                <input type="number" id="act-duration" min="1" placeholder="60">
            </div>
            <div class="dialog-actions">
                <button value="cancel" formnovalidate>Cancel</button>
                <button value="save" class="btn-primary">Save</button>
            </div>
        </form>
    </dialog>
`;

export class HealthDayScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private detail: HealthDayDetail | null = null;
    private loadSequence = 0;
    private dateValue = '';
    private dialogHost: HTMLElement | null = null;
    private readonly log = createComponentLogger('health-day-screen');

    set date(value: string) {
        this.dateValue = value;
    }

    setLoading(): void {
        this.detail?.showLoading();
    }

    setError(err: unknown): void {
        if (err instanceof Error) {
            this.detail?.showError(err.stack ?? err.message);
        } else {
            this.detail?.showError(String(err));
        }
    }

    clearStatus(): void {
        this.detail?.hideLoading();
    }

    connectedCallback(): void {
        if (!this.initialized) {
            this.initialized = true;
            const page = buildSectionPage(this, 'Health', 'health', '/health');

            this.detail = document.createElement('health-day-detail') as HealthDayDetail;
            this.detail.dateContext = this.dateValue;
            this.detail.showLoading();
            page.content.appendChild(this.detail);

            this.dialogHost = document.createElement('div');
            page.content.appendChild(this.dialogHost);
            this.dialogHost.appendChild(addActivityTemplate.content.cloneNode(true));

            this.wireDetail();
            this.wireAddDialog();
        }

        if (this.detail) {
            this.detail.dateContext = this.dateValue;
        }
        void this.loadData();
    }

    private wireDetail(): void {
        if (!this.detail) return;
        this.detail.addEventListener(HEALTH_EVENTS.ADD_WORKOUT, (event: AddWorkoutEvent) => {
            this.openManualAddDialog(event.detail.date);
        });

        this.detail.addEventListener(HEALTH_EVENTS.ADD_FOOD, (event: AddFoodEvent) => {
            navigate(`/health/food-entry/${encodeURIComponent(event.detail.date)}/${encodeURIComponent(event.detail.meal)}`);
        });

        this.detail.addEventListener(HEALTH_EVENTS.EDIT_FOOD, (event: EditFoodEvent) => {
            navigate(`/health/nutrition/${encodeURIComponent(event.detail.entry.id)}`);
        });

        this.detail.addEventListener(HEALTH_EVENTS.EDIT_WORKOUT, (event: EditWorkoutEvent) => {
            navigate(`/health/activity/${encodeURIComponent(event.detail.activity.id)}`);
        });
    }

    private wireAddDialog(): void {
        const dialog = this.querySelector('#activity-dialog') as HTMLDialogElement | null;
        const form = this.querySelector('#activity-form') as HTMLFormElement | null;
        if (!dialog || !form) return;

        dialog.addEventListener('close', () => {
            if (dialog.returnValue !== 'save') {
                form.reset();
                return;
            }

            const title = (this.querySelector('#act-title') as HTMLInputElement | null)?.value ?? '';
            const type = (this.querySelector('#act-type') as HTMLSelectElement | null)?.value ?? 'other';
            const date = (this.querySelector('#act-date') as HTMLInputElement | null)?.value ?? '';
            const durationStr = (this.querySelector('#act-duration') as HTMLInputElement | null)?.value ?? '';
            const duration = durationStr ? parseInt(durationStr, 10) : undefined;

            if (!title || !date) {
                form.reset();
                return;
            }

            void this.saveManualActivity({
                title,
                type: type as ActivityType,
                date,
                duration_minutes: duration,
            });

            form.reset();
        });
    }

    private async saveManualActivity(data: {
        title: string;
        type: ActivityType;
        date: string;
        duration_minutes?: number;
    }): Promise<void> {
        return safeExec(this, this.log, async () => {
            await HealthService.createActivity(data);
            await this.loadData();
        });
    }

    private openManualAddDialog(date: string): void {
        const dialog = this.querySelector('#activity-dialog') as HTMLDialogElement | null;
        const dateInput = this.querySelector('#act-date') as HTMLInputElement | null;
        if (!dialog || !dateInput) return;
        dateInput.value = date;
        dialog.showModal();
    }

    private async loadData(): Promise<void> {
        if (!this.detail) return;

        const currentLoad = ++this.loadSequence;
        this.detail.dateContext = this.dateValue;
        return safeExec(this, this.log, async () => {
            const [activities, nutrition] = await Promise.all([
                HealthService.fetchActivitiesByDate(this.dateValue),
                HealthService.fetchConsumptionByDate(this.dateValue),
            ]);

            // Story 116: ConsumptionEntry references food_item_id; the day detail
            // needs the food items to render names. Fetch in parallel — typically
            // a handful per day, so a few extra round trips are fine.
            const uniqueFoodIds = [...new Set(nutrition.map((e) => e.food_item_id))];
            const foodItems = await Promise.all(uniqueFoodIds.map((id) => HealthService.fetchFoodItem(id)));
            const foodItemsById = new Map(foodItems.filter((it) => it !== null).map((it) => [it!.id, it!] as const));

            // Story 077: resolve source_meal_id → name for entries logged from a meal template.
            const uniqueMealIds = [...new Set(nutrition.map((e) => e.source_meal_id).filter((id): id is string => Boolean(id)))];
            const meals = await Promise.all(uniqueMealIds.map((id) => HealthService.fetchMeal(id).catch(() => null)));
            const mealsById = new Map(meals.filter((m) => m !== null).map((m) => [m!.id, m!] as const));

            if (currentLoad !== this.loadSequence || !this.detail) return;

            this.detail.activities = activities;
            this.detail.foodItemsById = foodItemsById;
            this.detail.mealsById = mealsById;
            this.detail.nutrition = nutrition;
            this.detail.showContent();
        }, { errorMessage: `Failed to load detail for ${this.dateValue}` });
    }

}

customElements.define('health-day-screen', HealthDayScreen);
